import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Plus, Trash2, X, Upload, Video } from 'lucide-react';
import API from '../../utils/api';
import AdminLayout from './AdminLayout';
import toast from 'react-hot-toast';

const MUSCLE_GROUPS = ['chest','back','shoulders','arms','biceps','triceps','legs','glutes','core','abs','cardio','full-body','other'];

const emptyForm = {
  title: '', description: '', instructions: '', muscleGroup: 'chest',
  difficulty: 'beginner', equipmentNeeded: '', sets: '', reps: '', duration: '',
  isPublic: true
};

export default function AdminExercises() {
  const [exercises, setExercises] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [imageFile, setImageFile] = useState(null);
  const [videoFile, setVideoFile] = useState(null);
  const [saving, setSaving] = useState(false);
  const [filterMuscle, setFilterMuscle] = useState('all');

  const load = () => {
    const q = filterMuscle !== 'all' ? `?muscleGroup=${filterMuscle}` : '';
    API.get(`/exercises${q}`).then(r => setExercises(r.data)).catch(() => {}).finally(() => setLoading(false));
  };
  useEffect(load, [filterMuscle]);

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value === 'true' ? true : e.target.value === 'false' ? false : e.target.value });

  const handleSave = async () => {
    if (!form.title || !form.muscleGroup) { toast.error('Fill required fields'); return; }
    setSaving(true);
    try {
      const data = new FormData();
      Object.keys(form).forEach(k => data.append(k, form[k]));
      if (imageFile) data.append('image', imageFile);
      if (videoFile) data.append('video', videoFile);
      await API.post('/exercises', data, { headers: { 'Content-Type': 'multipart/form-data' } });
      toast.success('Exercise added!');
      setModal(false); setForm(emptyForm); setImageFile(null); setVideoFile(null); load();
    } catch (err) { toast.error(err.response?.data?.message || 'Error saving'); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this exercise?')) return;
    try { await API.delete(`/exercises/${id}`); toast.success('Deleted'); load(); }
    catch { toast.error('Error deleting'); }
  };

  return (
    <AdminLayout title="Exercises Management">
      <div className="flex flex-col sm:flex-row gap-4 mb-6 items-start sm:items-center justify-between">
        <div className="flex gap-2 flex-wrap">
          <button onClick={() => setFilterMuscle('all')} className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all ${filterMuscle === 'all' ? 'bg-orange-500 text-white' : 'bg-white/5 text-gray-400 border border-white/10'}`}>All</button>
          {MUSCLE_GROUPS.map(mg => (
            <button key={mg} onClick={() => setFilterMuscle(mg)} className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all capitalize ${filterMuscle === mg ? 'bg-orange-500 text-white' : 'bg-white/5 text-gray-400 border border-white/10'}`}>{mg}</button>
          ))}
        </div>
        <button onClick={() => { setModal(true); setForm(emptyForm); }} className="btn-fire flex items-center gap-2 text-sm py-2.5 px-4 flex-shrink-0">
          <Plus size={16} /> Add Exercise
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><div className="w-10 h-10 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" /></div>
      ) : exercises.length === 0 ? (
        <div className="text-center py-20 text-gray-500">No exercises found. Add one!</div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {exercises.map(ex => (
            <div key={ex._id} className="glass rounded-xl overflow-hidden group">
              <div className="relative h-40 bg-gray-900">
                {ex.image ? <img src={ex.image} alt={ex.title} className="w-full h-full object-cover" /> :
                  <div className="w-full h-full flex items-center justify-center text-gray-700 text-4xl">💪</div>}
                {ex.video && <div className="absolute top-2 right-2 bg-orange-500/80 rounded-full p-1"><Video size={12} className="text-white" /></div>}
                <div className="absolute bottom-2 left-2 text-xs bg-black/70 rounded-full px-2 py-0.5 text-gray-300 capitalize">{ex.muscleGroup}</div>
              </div>
              <div className="p-4">
                <div className="flex items-start justify-between">
                  <div>
                    <h3 className="text-white font-semibold line-clamp-1">{ex.title}</h3>
                    <span className={`text-xs capitalize ${ex.difficulty === 'beginner' ? 'text-green-400' : ex.difficulty === 'intermediate' ? 'text-yellow-400' : 'text-red-400'}`}>{ex.difficulty}</span>
                  </div>
                  <button onClick={() => handleDelete(ex._id)} className="p-1.5 text-red-400 hover:bg-red-400/10 rounded-lg"><Trash2 size={15} /></button>
                </div>
                {!ex.isPublic && <div className="text-yellow-400 text-xs mt-1">🔒 Private</div>}
              </div>
            </div>
          ))}
        </div>
      )}

      {modal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center px-4">
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
            className="bg-[#0d0d14] border border-white/10 rounded-2xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-5">
              <h2 className="text-white font-bold text-xl">Add Exercise</h2>
              <button onClick={() => setModal(false)}><X size={20} className="text-gray-400" /></button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="sm:col-span-2">
                <label className="text-gray-400 text-xs block mb-1">Title *</label>
                <input className="input-dark text-sm py-2" name="title" value={form.title} onChange={handleChange} placeholder="e.g. Barbell Bench Press" />
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Muscle Group *</label>
                <select className="input-dark text-sm py-2" name="muscleGroup" value={form.muscleGroup} onChange={handleChange}>
                  {MUSCLE_GROUPS.map(mg => <option key={mg} value={mg} className="bg-[#0d0d14] capitalize">{mg}</option>)}
                </select>
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Difficulty</label>
                <select className="input-dark text-sm py-2" name="difficulty" value={form.difficulty} onChange={handleChange}>
                  {['beginner','intermediate','advanced'].map(d => <option key={d} value={d} className="bg-[#0d0d14]">{d}</option>)}
                </select>
              </div>
              {[
                { name: 'sets', label: 'Sets', placeholder: '3-4' },
                { name: 'reps', label: 'Reps', placeholder: '8-12' },
                { name: 'duration', label: 'Duration', placeholder: '30 sec' },
                { name: 'equipmentNeeded', label: 'Equipment', placeholder: 'Barbell, Bench' },
              ].map(f => (
                <div key={f.name}>
                  <label className="text-gray-400 text-xs block mb-1">{f.label}</label>
                  <input className="input-dark text-sm py-2" name={f.name} value={form[f.name]} onChange={handleChange} placeholder={f.placeholder} />
                </div>
              ))}
              <div className="sm:col-span-2">
                <label className="text-gray-400 text-xs block mb-1">Description</label>
                <textarea className="input-dark text-sm min-h-[80px]" name="description" value={form.description} onChange={handleChange} />
              </div>
              <div className="sm:col-span-2">
                <label className="text-gray-400 text-xs block mb-1">Instructions (step by step)</label>
                <textarea className="input-dark text-sm min-h-[100px]" name="instructions" value={form.instructions} onChange={handleChange} placeholder="1. Lie flat on bench...&#10;2. Grip bar..." />
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1 flex items-center gap-1"><Upload size={12} /> Exercise Image</label>
                <input type="file" accept="image/*" onChange={e => setImageFile(e.target.files[0])} className="text-gray-400 text-xs w-full" />
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1 flex items-center gap-1"><Video size={12} /> Exercise Video</label>
                <input type="file" accept="video/*" onChange={e => setVideoFile(e.target.files[0])} className="text-gray-400 text-xs w-full" />
              </div>
              <div className="flex items-center gap-3">
                <label className="text-gray-400 text-xs">Visibility:</label>
                <label className="flex items-center gap-1.5 cursor-pointer">
                  <input type="radio" name="isPublic" value="true" checked={form.isPublic === true} onChange={handleChange} />
                  <span className="text-gray-300 text-xs">Public</span>
                </label>
                <label className="flex items-center gap-1.5 cursor-pointer">
                  <input type="radio" name="isPublic" value="false" checked={form.isPublic === false} onChange={handleChange} />
                  <span className="text-gray-300 text-xs">Private</span>
                </label>
              </div>
            </div>
            <div className="flex justify-end gap-3 mt-6">
              <button onClick={() => setModal(false)} className="px-4 py-2 text-gray-400 border border-white/10 rounded-lg text-sm">Cancel</button>
              <button onClick={handleSave} disabled={saving} className="btn-fire px-5 py-2 text-sm">
                {saving ? <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin inline-block" /> : 'Save Exercise'}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AdminLayout>
  );
}
